# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if amount > self.balance:
            return "Insufficient funds"
        else:
            self.balance -= amount
            return self.balance

class TransactionProcessor:
    def process_transaction(self, account, transaction):
        account_type, amount = transaction
        if account_type == "deposit":
            account.deposit(amount)
        elif account_type == "withdraw":
            result = account.withdraw(amount)
            if isinstance(result, str):
                return result
            else:
                return result